func sparklinePoints(history []float64) string {
	if len(history) == 0 {
		return ""
	}
	minVal, maxVal := history[0], history[0]
	for _, v := range history {
		if v < minVal {
			minVal = v
		}
		if v > maxVal {
			maxVal = v
		}
	}
	spread := maxVal - minVal
	if spread == 0 {
		spread = 1
	}
	points := make([]string, len(history))
	for i, v := range history {
		x := float64(i) / math.Max(float64(len(history)-1), 1) * 100
		y := 28 - ((v-minVal)/spread)*26
		points[i] = fmt.Sprintf("%.1f,%.1f", x, y)
	}
	return strings.Join(points, " ")
}

